var porSol = meioDiaSolar + duracaoDia/2;


// HORAS SOLARES DECORRIDAS

var horasSolares;

if (horaAtual <= nascerSol) {
    horasSolares = 0;
} 
else if (horaAtual >= porSol) {
    horasSolares = duracaoDia;
} 
else {
    horasSolares = horaAtual - nascerSol;
}

// Proteção
if (horasSolares <= 0) return 0;


// CÁLCULO DO FC

var FC = (energia / (capacity * horasSolares)) * 100;


// CLAMP DE SEGURANÇA (0% a 100%)

if (isNaN(FC) || !isFinite(FC)) {
    return 0;
}

if (FC > 100) FC = 100;
if (FC < 0) FC = 0;

return FC;

